  const replaceKeyDeep = (obj) => {
    if (Array.isArray(obj)) return obj.map(replaceKeyDeep)
    if (obj && typeof obj === "object") {
      const out = {}
      for (const [k, v] of Object.entries(obj)) {
        const nk = k === "mr_kowalski" ? "John Ronald Kowalski" : k
        out[nk] = replaceKeyDeep(v)
      }
      return out
    }
    return obj
  }

  const updated = replaceKeyDeep(data)
  const yaml = space.utils.yaml.stringify(updated)
  await space.api.fileWrite(path, yaml, "utf8")
  return yaml
})()

